import json
import boto3
import logging
import re
import os

logger = logging.getLogger()
logger.setLevel(logging.INFO)

sns_client = boto3.client('sns')

ALLOWED_TOPIC_ARNS = os.environ.get('ALLOWED_TOPIC_ARNS', '').split(',')

ALLOWED_NOTIFICATION_TYPES = {
    'alert',
    'info',
    'warning',
    'critical',
    'system',
    'user_event'
}

MAX_MESSAGE_LENGTH = 256 * 1024  # 256 KB SNS limit
MAX_SUBJECT_LENGTH = 100


def validate_topic_arn(topic_arn):
    """Validate that the topic ARN is well-formed and in the allowlist."""
    if not topic_arn or not isinstance(topic_arn, str):
        raise ValueError("Topic ARN must be a non-empty string")

    arn_pattern = r'^arn:aws:sns:[a-z0-9-]+:\d{12}:[a-zA-Z0-9_-]+$'
    if not re.match(arn_pattern, topic_arn):
        raise ValueError(f"Invalid SNS topic ARN format: {topic_arn}")

    if topic_arn not in ALLOWED_TOPIC_ARNS:
        raise ValueError(f"Topic ARN not in allowlist: {topic_arn}")

    return topic_arn


def validate_message(message):
    """Validate message content."""
    if not message or not isinstance(message, str):
        raise ValueError("Message must be a non-empty string")

    if len(message) > MAX_MESSAGE_LENGTH:
        raise ValueError(f"Message exceeds maximum length of {MAX_MESSAGE_LENGTH} bytes")

    return message


def validate_notification_type(notification_type):
    """Validate notification type against allowed types."""
    if not notification_type or not isinstance(notification_type, str):
        raise ValueError("Notification type must be a non-empty string")

    notification_type = notification_type.lower().strip()

    if notification_type not in ALLOWED_NOTIFICATION_TYPES:
        raise ValueError(
            f"Invalid notification type: {notification_type}. "
            f"Allowed types: {ALLOWED_NOTIFICATION_TYPES}"
        )

    return notification_type


def validate_subject(subject):
    """Validate optional subject line."""
    if subject is None:
        return None

    if not isinstance(subject, str):
        raise ValueError("Subject must be a string")

    subject = subject.strip()
    if len(subject) > MAX_SUBJECT_LENGTH:
        raise ValueError(f"Subject exceeds maximum length of {MAX_SUBJECT_LENGTH}")

    if not re.match(r'^[a-zA-Z0-9\s\-_.:!?]+$', subject):
        raise ValueError("Subject contains invalid characters")

    return subject


def publish_message(topic_arn, message, notification_type, subject=None, message_attributes=None):
    """Publish a message to the specified SNS topic with proper validation."""
    validated_arn = validate_topic_arn(topic_arn)
    validated_message = validate_message(message)
    validated_type = validate_notification_type(notification_type)
    validated_subject = validate_subject(subject)

    structured_message = json.dumps({
        'notification_type': validated_type,
        'content': validated_message,
        'timestamp': _get_timestamp()
    })

    sns_params = {
        'TopicArn': validated_arn,
        'Message': structured_message,
        'MessageAttributes': {
            'notification_type': {
                'DataType': 'String',
                'StringValue': validated_type
            }
        }
    }

    if validated_subject:
        sns_params['Subject'] = validated_subject

    if message_attributes and isinstance(message_attributes, dict):
        for key, value in message_attributes.items():
            if isinstance(key, str) and re.match(r'^[a-zA-Z0-9_.-]+$', key):
                if isinstance(value, str) and len(value) <= 256:
                    sns_params['MessageAttributes'][key] = {
                        'DataType': 'String',
                        'StringValue': value
                    }

    response = sns_client.publish(**sns_params)
    return response


def _get_timestamp():
    """Get current UTC timestamp."""
    from datetime import datetime, timezone
    return datetime.now(timezone.utc).isoformat()


def lambda_handler(event, context):
    """
    Lambda handler for publishing SNS notifications.

    Expected event structure:
    {
        "topic_arn": "arn:aws:sns:us-east-1:123456789012:MyTopic",
        "message": "Your notification message",
        "notification_type": "alert",
        "subject": "Optional subject line",
        "message_attributes": {"key": "value"},
        "batch": [
            {
                "topic_arn": "...",
                "message": "...",
                "notification_type": "..."
            }
        ]
    }
    """
    logger.info("Received event for notification processing")

    results = []

    try:
        if 'batch' in event and isinstance(event['batch'], list):
            if len(event['batch']) > 25:
                return {
                    'statusCode': 400,
                    'body': json.dumps({
                        'error': 'Batch size exceeds maximum of 25 messages'
                    })
                }

            for idx, item in enumerate(event['batch']):
                try:
                    response = publish_message(
                        topic_arn=item.get('topic_arn'),
                        message=item.get('message'),
                        notification_type=item.get('notification_type'),
                        subject=item.get('subject'),
                        message_attributes=item.get('message_attributes')
                    )
                    results.append({
                        'index': idx,
                        'status': 'success',
                        'message_id': response.get('MessageId')
                    })
                    logger.info(f"Batch message {idx} published: {response.get('MessageId')}")
                except (ValueError, Exception) as e:
                    results.append({
                        'index': idx,
                        'status': 'failed',
                        'error': str(e)
                    })
                    logger.error(f"Batch message {idx} failed: {str(e)}")

        else:
            topic_arn = event.get('topic_arn')
            message = event.get('message')
            notification_type = event.get('notification_type')
            subject = event.get('subject')
            message_attributes = event.get('message_attributes')

            response = publish_message(
                topic_arn=topic_arn,
                message=message,
                notification_type=notification_type,
                subject=subject,
                message_attributes=message_attributes
            )

            results.append({
                'status': 'success',
                'message_id': response.get('MessageId')
            })
            logger.info(f"Message published successfully: {response.get('MessageId')}")

        return {
            'statusCode': 200,
            'body': json.dumps({
                'message': 'Notifications processed',
                'results': results
            })
        }

    except ValueError as ve:
        logger.error(f"Validation error: {str(ve)}")
        return {
            'statusCode': 400,
            'body': json.dumps({
                'error': 'Validation error',
                'details': str(ve)
            })
        }
    except sns_client.exceptions.NotFoundException:
        logger.error("SNS topic not found")
        return {
            'statusCode': 404,
            'body': json.dumps({
                'error': 'SNS topic not found'
            })
        }
    except sns_client.exceptions.AuthorizationErrorException:
        logger.error("Not authorized to publish to SNS topic")
        return {
            'statusCode': 403,
            'body': json.dumps({
                'error': 'Not authorized to publish to this topic'
            })
        }
    except Exception as e:
        logger.error(f"Unexpected error: {str(e)}")
        return {
            'statusCode': 500,
            'body': json.dumps({
                'error': 'Internal server error'
            })
        }